                    if op is not None:
                        errors.append(f"Line {i+1}: multiple operations in one block")
                    op = m.group(1)
                    path = m.group(2).strip()
            elif l.startswith('@@'):
                # Hunk header - OK
                pass
            else:
                body_lines.append(l)
            i += 1
        if i >= len(lines):
            errors.append(f"Line {start+1}: missing *** End Patch")
            break
        if op is None or path is None:
            errors.append(f"Line {start+1}: Begin Patch without operation: {body_lines[:5]}")
        else:
            ops.append((op, path, body_lines))
        i += 1
    else:
        i += 1

# Validate each operation
for op, path, body in ops:
    if op == 'Add File':
        # Every non-empty line should start with '+'
        nonempty = [l for l in body if l]
        bad = [l for l in nonempty if not l.startswith('+')]
        if bad:
            errors.append(f"Add File {path}: {len(bad)} non-prefixed lines (expected all '+')")
            for b in bad[:3]:
                errors.append(f"  {repr(b[:80])}")
    elif op == 'Update File':
        # Group by hunks
        hunks = []
        current = None
        for l in body:
            if l.startswith('@@'):
                if current is not None:
                    hunks.append(current)
                current = []
            elif current is not None:
                current.append(l)
        if current is not None:
            hunks.append(current)
        for j, h in enumerate(hunks):
            content = [l for l in h if l != '']
            bad = [l for l in content if not l.startswith(('+', '-'))]
            if bad:
                errors.append(f"Update File {path} hunk {j+1}: {len(bad)} unprefixed non-empty lines")
                for b in bad[:3]:
                    errors.append(f"  {repr(b[:80])}")
    elif op == 'Delete File':
        pass  # no body expected

if errors:
    print(f"ERRORS ({len(errors)}):")
    for e in errors[:30]:
        print(f"  {e}")
else:
    print(f"PATCH VALID: {len(ops)} operations, all formatted correctly.")
    for op, path, body in ops:
        lines = len(body)
        print(f"  {op:13} {path:60} ({lines} body lines)")
EOF
